import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.stream.Materializer
import akka.util.ByteString
import scala.concurrent.Future
import akka.http.scaladsl.model._
import spray.json._

object WebhookService extends App {
  implicit val system = ActorSystem("WebhookService")
  implicit val materializer = Materializer(system)

  def fetchContentFromUrl(url: String): Future[String] = {
    Http().singleRequest(HttpRequest(uri = url)).flatMap { response =>
      response.entity.dataBytes.runFold(ByteString(""))(_ ++ _).map(bs => bs.decodeToString())
    }
  }

  def handleUrl(url: String): Unit = {
    fetchContentFromUrl(url).foreach(content => println(content))
  }
}